// QTP Supabase-only Health Monitor evaluator v4.2.1
const source = $('Prepare Supabase Health Query').first().json || {};
const expected = source.expected_counts || {};
const actualRows = $input.all().map(i => i.json || {});
const actual = Object.fromEntries(actualRows.map(r => [String(r.metric_name), Number(r.metric_value ?? 0)]));
const tableRows = Object.keys(expected).sort().map(table_name => {
  const expected_min = Number(expected[table_name] ?? 0);
  const current_count = Number(actual[table_name] ?? -1);
  const status = current_count >= expected_min ? 'OK' : 'BELOW_EXPECTED';
  return { table_name, expected_min, current_count, delta_vs_min: current_count - expected_min, status };
});
const discrepancies = tableRows.filter(r => r.status !== 'OK');
const deadLetters24h = Number(actual.__dead_letters_24h ?? 0);
const openPositions = Number(actual.__latest_open_positions ?? 0);
const notFullyProtected = Number(actual.__latest_not_fully_protected ?? 0);
const blockers = Number(actual.__latest_new_entry_blockers ?? 0);
const safetyIssues = [];
if (deadLetters24h > 0) safetyIssues.push(`dead_letters_24h=${deadLetters24h}`);
if (notFullyProtected > 0) safetyIssues.push(`not_fully_protected=${notFullyProtected}`);
if (blockers > 0) safetyIssues.push(`new_entry_blockers=${blockers}`);
const status = discrepancies.length || safetyIssues.length ? 'ALERT' : 'OK';
const report = {
  monitor_version: source.monitor_version,
  checked_at: new Date().toISOString(),
  status,
  total_tables_checked: tableRows.length,
  discrepancies,
  dead_letters_24h: deadLetters24h,
  open_positions: openPositions,
  not_fully_protected: notFullyProtected,
  new_entry_blockers: blockers,
  safety_issues: safetyIssues,
};
return [{ json: report }];

// Send Telegram only on discrepancies/safety issues. Healthy runs stay silent.
const report = $input.first().json || {};
if (report.status === 'OK') {
  return [{ json: { ...report, alert_sent: false, alert_reason: 'healthy_no_alert' } }];
}
const bot = $vars.TELEGRAM_BOT_TOKEN || '';
const chat = $vars.TELEGRAM_CHAT_ID || $vars.TELEGRAM_PERSONAL_CHAT_ID || '';
if (!bot || !chat) {
  return [{ json: { ...report, alert_sent: false, alert_error: 'missing_telegram_vars' } }];
}
const top = (report.discrepancies || []).slice(0, 8).map(r => `${r.table_name}: ${r.current_count}/${r.expected_min}`).join('\n');
const text = [
  '🚨 QTP SUPABASE HEALTH ALERT',
  `Status: ${report.status}`,
  `Checked: ${report.checked_at}`,
  `Tables checked: ${report.total_tables_checked}`,
  `Discrepancies: ${(report.discrepancies || []).length}`,
  top ? `\nBelow expected:\n${top}` : '',
  `\nSafety: dead_letters_24h=${report.dead_letters_24h}, open_positions=${report.open_positions}, not_fully_protected=${report.not_fully_protected}, blockers=${report.new_entry_blockers}`,
].filter(Boolean).join('\n');
const resp = await this.helpers.httpRequest({
  method: 'POST',
  url: `https://api.telegram.org/bot${bot}/sendMessage`,
  headers: { 'Content-Type': 'application/json' },
  body: { chat_id: chat, text, disable_web_page_preview: true },
  json: true,
  timeout: 20000,
});
return [{ json: { ...report, alert_sent: true, telegram_ok: resp.ok === true } }];

